import React, { useState } from 'react';

const App = () => {
  const [channel, setChannel] = useState('Channel 1');
  const [typing, setTyping] = useState({});
  const [messages, setMessages] = useState({});

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="w-2/3 bg-white p-4 rounded-lg shadow-md">
        <div className="flex items-center justify-between mb-4">
          <h2 className="text-lg font-bold">{channel}</h2>
          <button className="bg-[#B7D7CD] py-2 px-4 rounded-md">Switch Channel</button>
        </div>
        <div className="flex items-center mb-4">
          <img src="https://via.placeholder.com/40" className="w-10 h-10 rounded-full mr-4"/>
          <input type="text" placeholder="Type a message..." className="w-full py-2 px-4 rounded-md bg-[#C06C88]"/>
        </div>
        <div className="bg-[#090a0f] p-4 rounded-md">
          <ul className="list-none mb-0">
            {Object.keys(messages).map((message, index) => (
              <li key={index} className="mb-2">
                <span className="block text-sm font-bold mr-2 text-[#B7D7CD]">{message}</span>
                <span className="block text-sm text-white">{messages[message]}</span>
              </li>
            ))}
          </ul>
        </div>
        <div className="bg-[#090a0f] p-4 rounded-md mb-4">
          {Object.keys(typing).map((user, index) => (
            <div key={index} className="mb-2">
              <span className="block text-sm font-bold mr-2 text-[#B7D7CD]">{user}</span>
              <span className="block text-sm text-white">Typing...</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default App;
